"use client";

import { UserButton, useUser } from "@clerk/nextjs";
import { usePathname } from "next/navigation";
import Link from "next/link";
import { 
  LayoutDashboard, 
  Settings, 
  BookOpen, 
  Users, 
  Handshake, 
  Image as ImageIcon, 
  ChevronRight,
  Bell,
  Search,
  Menu,
  X,
  Sparkles,
  Command,
  Monitor
} from "lucide-react";
import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { updateUserRole } from "@/app/actions/user";

export default function AdminLayout({ children }: { children: React.ReactNode }) {
  const { user, isLoaded } = useUser();
  const pathname = usePathname();
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isMobile, setIsMobile] = useState(false);

  // Handle window resize for sidebar
  useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.innerWidth < 1024);
      if (window.innerWidth < 1024) setIsSidebarOpen(false);
    };
    handleResize();
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  // Auto-assign SUPER_ADMIN to first user if no role exists
  useEffect(() => {
    if (isLoaded && user && !user.publicMetadata.role) {
      const timer = setTimeout(async () => {
         await updateUserRole(user.id, "SUPER_ADMIN");
      }, 1000);
      return () => clearTimeout(timer);
    }
  }, [isLoaded, user]);

  if (!isLoaded) {
    return (
      <div className="min-h-screen bg-[#050505] flex items-center justify-center">
        <div className="relative">
          <div className="size-16 border-4 border-white/5 border-t-primary rounded-full animate-spin"></div>
          <div className="absolute inset-0 flex items-center justify-center">
             <Command className="text-primary w-6 h-6 animate-pulse" />
          </div>
        </div>
      </div>
    );
  }

  const navItems = [
    { name: "Dashboard", href: "/admin", icon: LayoutDashboard },
    { name: "Users", href: "/admin/users", icon: Users },
    { name: "Global Settings", href: "/admin/settings", icon: Settings },
    { name: "Page Content", href: "/admin/sections", icon: Monitor },
    { name: "Programs", href: "/admin/programs", icon: Sparkles },
    { name: "Courses", href: "/admin/courses", icon: BookOpen },
    { name: "Team Members", href: "/admin/team", icon: Users },
    { name: "Partners", href: "/admin/partners", icon: Handshake },
    { name: "Gallery", href: "/admin/gallery", icon: ImageIcon },
  ];

  return (
    <div className="min-h-screen bg-[#080808] text-slate-300 flex overflow-hidden font-sans">
      {/* Mobile Overlay */}
      <AnimatePresence>
        {isMobile && isSidebarOpen && (
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={() => setIsSidebarOpen(false)}
            className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[60] lg:hidden"
          />
        )}
      </AnimatePresence>

      {/* Sidebar */}
      <aside 
        className={`
          ${isSidebarOpen ? "w-[280px]" : "w-[90px]"} 
          fixed lg:relative inset-y-0 left-0 z-[70]
          bg-[#0A0A0A] border-r border-white/5 
          transition-all duration-500 ease-[cubic-bezier(0.23,1,0.32,1)]
          flex flex-col group
          ${!isSidebarOpen && isMobile ? "-translate-x-full" : "translate-x-0"}
        `}
      >
        {/* Sidebar Header */}
        <div className="h-24 flex items-center px-6 border-b border-white/5 relative overflow-hidden">
           <div className="absolute inset-0 bg-gradient-to-br from-primary/5 to-transparent opacity-50"></div>
           <div className="size-12 bg-gradient-to-br from-primary to-blue-500 rounded-2xl flex items-center justify-center flex-shrink-0 shadow-[0_0_20px_rgba(59,130,246,0.2)] relative z-10">
              <Command className="text-white w-6 h-6" />
           </div>
           <div className={`ml-4 transition-all duration-300 ${isSidebarOpen ? "opacity-100 translate-x-0" : "opacity-0 -translate-x-4 pointer-events-none"}`}>
              <span className="block font-black text-white text-lg tracking-tighter uppercase whitespace-nowrap">Orphosys</span>
              <span className="block text-[10px] font-black text-primary uppercase tracking-[0.2em] -mt-1">Command Center</span>
           </div>
        </div>

        {/* Navigation */}
        <nav className="flex-grow py-8 px-4 space-y-1.5 overflow-y-auto scrollbar-hide">
          {navItems.map((item) => {
            const isActive = pathname === item.href;
            const Icon = item.icon;
            
            if (item.name === "Users" && user?.publicMetadata.role !== "SUPER_ADMIN") {
              return null;
            }

            return (
              <Link
                key={item.name}
                href={item.href}
                className={`flex items-center gap-4 px-4 py-3.5 rounded-2xl transition-all relative group/item ${
                  isActive 
                    ? "bg-white/[0.03] text-white shadow-[inset_0_0_20px_rgba(255,255,255,0.02)]" 
                    : "text-slate-500 hover:text-white hover:bg-white/[0.02]"
                }`}
              >
                {isActive && (
                  <motion.div 
                    layoutId="activeNav"
                    className="absolute left-0 w-1 h-6 bg-primary rounded-full"
                  />
                )}
                <Icon className={`w-5 h-5 flex-shrink-0 transition-transform duration-300 ${isActive ? "text-primary scale-110" : "group-hover/item:scale-110"}`} />
                <span className={`font-bold text-[13px] tracking-wide transition-all duration-300 ${isSidebarOpen ? "opacity-100" : "opacity-0 pointer-events-none w-0"}`}>
                  {item.name}
                </span>
                {isSidebarOpen && isActive && (
                  <ChevronRight className="ml-auto w-3.5 h-3.5 text-primary" />
                )}
              </Link>
            );
          })}
        </nav>

        {/* Sidebar Footer */}
        <div className="p-6 border-t border-white/5 bg-gradient-to-t from-white/[0.01] to-transparent">
           <div className={`flex items-center gap-3 transition-all ${isSidebarOpen ? "" : "justify-center"}`}>
              <div className="p-1 rounded-full bg-white/5 border border-white/10 shadow-inner">
                <UserButton 
                  appearance={{
                    elements: {
                      userButtonAvatarBox: "size-8",
                      userButtonTrigger: "focus:shadow-none"
                    }
                  }}
                />
              </div>
              {isSidebarOpen && (
                <div className="min-w-0">
                  <p className="text-xs font-black text-white truncate">{user?.fullName}</p>
                  <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest truncate">System Root</p>
                </div>
              )}
           </div>
        </div>
      </aside>

      {/* Main Content Viewport */}
      <div className="flex-grow flex flex-col min-w-0 h-screen relative">
        <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-[0.03] pointer-events-none"></div>

        {/* Navbar */}
        <header className="h-24 bg-[#0A0A0A]/80 backdrop-blur-xl border-b border-white/5 px-8 flex items-center justify-between sticky top-0 z-[40]">
           <div className="flex items-center gap-6">
              <button 
                onClick={() => setIsSidebarOpen(!isSidebarOpen)}
                className="size-11 flex items-center justify-center rounded-xl bg-white/[0.03] border border-white/5 text-slate-400 hover:text-white hover:border-primary/50 transition-all active:scale-95 shadow-sm"
              >
                {isSidebarOpen ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
              </button>
              <div className="hidden md:flex items-center bg-white/[0.02] border border-white/5 rounded-2xl px-5 py-3 w-96 focus-within:border-primary/40 focus-within:bg-white/[0.04] transition-all group">
                 <Search className="w-4 h-4 text-slate-500 mr-3 group-focus-within:text-primary transition-colors" />
                 <input 
                  type="text" 
                  placeholder="Universal command search..." 
                  className="bg-transparent border-none outline-none text-[13px] w-full font-medium text-slate-400 focus:text-white" 
                 />
                 <span className="text-[10px] font-black text-slate-700 bg-black px-2 py-0.5 rounded-md border border-white/5">⌘K</span>
              </div>
           </div>

           <div className="flex items-center gap-8">
              <div className="hidden sm:flex items-center gap-2">
                 <div className="size-2 bg-emerald-500 rounded-full animate-pulse"></div>
                 <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Network Online</span>
              </div>

              <button className="size-11 flex items-center justify-center rounded-xl bg-white/[0.03] border border-white/5 text-slate-400 hover:text-primary transition-all relative">
                 <Bell className="w-5 h-5" />
                 <span className="absolute top-3 right-3 size-2 bg-primary rounded-full border-2 border-[#0A0A0A]"></span>
              </button>

              <div className="flex items-center gap-4 pl-6 border-l border-white/5">
                 <div className="text-right hidden sm:block">
                    <p className="text-xs font-black text-white leading-none">{user?.fullName}</p>
                    <p className="text-[9px] font-black text-primary uppercase tracking-[0.2em] mt-1.5">
                      {user?.publicMetadata.role ? (user.publicMetadata.role as string).replace("_", " ") : "ADMIN"}
                    </p>
                 </div>
                 <div className="size-11 rounded-2xl bg-gradient-to-br from-primary/20 to-blue-500/20 border border-primary/20 flex items-center justify-center overflow-hidden">
                    <UserButton />
                 </div>
              </div>
           </div>
        </header>

        {/* Main Content Area */}
        <main className="flex-1 overflow-y-auto relative scroll-smooth bg-transparent">
          <div className="p-8 lg:p-12 max-w-[1600px] mx-auto min-h-full flex flex-col">
            {children}
            
            {/* Footer note */}
            <footer className="mt-auto pt-12 pb-6 flex justify-between items-center opacity-20 border-t border-white/5">
               <p className="text-[10px] font-black uppercase tracking-widest">Orphosys Foundation OS</p>
               <p className="text-[10px] font-black uppercase tracking-widest">v2.0.4 r.1337</p>
            </footer>
          </div>
        </main>
      </div>

      <style jsx global>{`
        ::-webkit-scrollbar { width: 6px; height: 6px; }
        ::-webkit-scrollbar-track { background: transparent; }
        ::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.05); border-radius: 10px; }
        ::-webkit-scrollbar-thumb:hover { background: rgba(255,255,255,0.1); }
        .scrollbar-hide::-webkit-scrollbar { display: none; }
        
        @keyframes fade-in {
          from { opacity: 0; transform: translateY(10px); }
          to { opacity: 1; transform: translateY(0); }
        }
        .animate-fade-in { animation: fade-in 0.6s cubic-bezier(0.23, 1, 0.32, 1) forwards; }
      `}</style>
    </div>
  );
}
